parameters.jsonBody:
={
  "blocks": [
    {
      "type": "header",
      "text": {
        "type": "plain_text",
        "text": "📊 FleetMind Weekly Report"
      }
    },
    {
      "type": "section",
      "text": {
        "type": "mrkdwn",
        "text": {{ JSON.stringify($json.report.substring(0, 2900)) }}
      }
    },
    {
      "type": "section",
      "fields": [
        { "type": "mrkdwn", "text": "*Fleet:* {{ $json.summary.fleet_total }} vehicles" },
        { "type": "mrkdwn", "text": "*Active:* {{ $json.summary.fleet_active }}" },
        { "type": "mrkdwn", "text": "*Maintenance:* {{ $json.summary.maintenance_critical }} critical" },
        { "type": "mrkdwn", "text": "*Fuel Waste:* ${{ $json.summary.fuel_waste_usd }}" }
      ]
    },
    {
      "type": "context",
      "elements": [
        { "type": "mrkdwn", "text": "FleetMind Weekly Report via n8n • {{ $json.timestamp }}" }
      ]
    }
  ]
}
